css:
.print-format {
  font-family: 'Helvetica Neue', Arial, sans-serif;
  padding: 20px;
  color: #333;
}
.report-header {
  text-align: center;
  border-bottom: 3px solid #1a5276;
  padding-bottom: 15px;
  margin-bottom: 20px;
}
.report-header h1 {
  color: #1a5276;
  font-size: 22px;
  margin: 5px 0;
  text-transform: uppercase;
  letter-spacing: 2px;
}
.report-header h2 {
  color: #2c3e50;
  font-size: 16px;
  font-weight: normal;
  margin: 5px 0;
}
.report-header .term-info {
  color: #7f8c8d;
  font-size: 12px;
}
.section-title {
  background-color: #1a5276;
  color: white;
  padding: 6px 12px;
  font-size: 12px;
  text-transform: uppercase;
  letter-spacing: 1px;
  margin: 15px 0 8px 0;
  border-radius: 3px;
}
.student-info-table {
  width: 100%;
  border-collapse: collapse;
  margin-bottom: 10px;
}
.student-info-table td {
  padding: 4px 8px;
  font-size: 11px;
  border: 1px solid #dee2e6;
}
.student-info-table .label-cell {
  background-color: #f8f9fa;
  font-weight: bold;
  width: 25%;
  color: #555;
}
.grades-table {
  width: 100%;
  border-collapse: collapse;
  margin-bottom: 10px;
}
.grades-table th {
  background-color: #2c3e50;
  color: white;
  padding: 6px 10px;
  font-size: 11px;
  text-align: left;
  border: 1px solid #2c3e50;
}
.grades-table td {
  padding: 5px 10px;
  font-size: 11px;
  border: 1px solid #dee2e6;
}
.grades-table tr:nth-child(even) {
  background-color: #f8f9fa;
}
.grade-A { color: #27ae60; font-weight: bold; }
.grade-B { color: #2980b9; font-weight: bold; }
.grade-C { color: #f39c12; font-weight: bold; }
.grade-D { color: #e67e22; font-weight: bold; }
.grade-E { color: #e74c3c; font-weight: bold; }
.grade-F { color: #c0392b; font-weight: bold; }
.summary-box {
  display: inline-block;
  border: 1px solid #dee2e6;
  border-radius: 4px;
  padding: 8px 15px;
  margin: 5px;
  text-align: center;
  min-width: 120px;
}
.summary-box .label {
  font-size: 10px;
  color: #7f8c8d;
  text-transform: uppercase;
}
.summary-box .value {
  font-size: 18px;
  font-weight: bold;
  color: #1a5276;
}
.comments-box {
  border: 1px solid #dee2e6;
  border-radius: 4px;
  padding: 10px;
  margin: 8px 0;
  background-color: #fefefe;
  font-size: 11px;
  line-height: 1.5;
}
.comments-box .comment-course {
  font-weight: bold;
  color: #2c3e50;
  margin-bottom: 2px;
}
.comments-box .comment-text {
  color: #555;
  margin-bottom: 8px;
  padding-left: 10px;
  border-left: 3px solid #1a5276;
}
.footer {
  text-align: center;
  color: #95a5a6;
  font-size: 9px;
  margin-top: 25px;
  padding-top: 10px;
  border-top: 1px solid #dee2e6;
}
.signature-line {
  margin-top: 30px;
  display: flex;
  justify-content: space-between;
}
.signature-line .sig {
  width: 30%;
  border-top: 1px solid #333;
  padding-top: 5px;
  font-size: 10px;
  text-align: center;
  color: #555;
}
